INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07450', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於「任務中心取向」的敘述，下列何者為錯誤？', '["任務中心建立在案主同意的基礎上，或是案主承認依法必須採取的行動", "任務中心經由持續的評鑑而發展和改變", "任務中心具有結構嚴謹的實務工作方法，社會工作者被視為界定與執行任務的專家", "任務中心旨在從問題進展到目標，從出了差錯到做出必要的改變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07451', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作者與兒童及家庭一起工作時，重要的價值與倫理的敘述，何者為錯誤？', '["為了尊重兒童自我抉擇（self-determination）的權利，若是兒童表達不願意因為受虐而被通報，社會工 作者應該尊重他的想法", "社會工作者應試著去尊重每個家庭處境的差異，而不是要求家庭順應傳統或主流社會的價值觀", "強調自我抉擇反應出著重優勢的觀點，即使是兒童，社會工作者仍應該鼓勵其建立可以為自己處遇做 決定的資源及技巧", "除了關係到生命的議題，兒童所說的大部分事情，社會工作者都應該謹守保密的義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07452', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會正義的敘述，何者為錯誤？', '["「社會工作者要挑戰社會不公平，並和容易受到傷害及壓迫的族群一起追求社會改變」是社會工作重 要的倫理準則之一", "社會正義是指存在人類關係中公平的程度，社會工作者所面臨的議題，大都和直接或間接不公平的情 境有關", "社會工作者應倡導政策與法律的改變，以改善社會條件和提升社會正義", "社會資源有限，社會工作者在提供服務的過程中，應該協助案主瞭解資源的限制，而能適應現況"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07453', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「少年瞞著父母買機車，要求社會工作者不能告訴父母，此時專業關係才建立，社會工作者該怎麼做？」 上述情境是陷於何種倫理兩難？', '["隱私守密原則與告知義務的倫理兩難", "自主自由原則與隱私守密原則的倫理兩難", "提出警告義務與隱私守密原則的倫理兩難", "隱私守密原則與最小傷害原則的倫理兩難"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07454', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「在會談過程中，案主可能會與社會工作者討論到一些企圖傷害他人的事情，此時社會工作者可以安排案 主在保護性的監督之下暫時隔離、告知可能被案主傷害的對象、請求司法單位的處理等方式來處理」，上 述的討論屬於社會工作者那一種法定義務？', '["報告的義務", "告知的義務", "提出警告的義務", "照顧的義務"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 32, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07455', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「社會工作者如果有所選擇的話，應該選擇一個對案主限制最少，最容易回復到原本生活形態的安置環 境」，這是屬於社會工作者那一項倫理原則？', '["生活品質原則", "最小傷害原則", "自由自主原則", "差別平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07456', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作者在心理衛生實務領域中的敘述，何者為錯誤？', '["社會工作者在心理衛生服務的實務運作中，必須瞭解案主心理的病症與狀態，對於某些族群尋求宗教 來協助解決心理困擾的作法，應該藉由醫學上的科學證據，來改善他們的錯誤認知", "社會工作者在心理衛生服務領域扮演多元角色，例如：個案管理者、倡導者、諮商者…等角色", "心理衛生服務領域常運用跨專業團隊的方式，由跨專業的精神病學、社會工作、護理、職業復健與藥 物濫用…等工作人員組成，以協助社區中需要心理衛生服務的案主", "社會工作者在心理衛生服務實務工作中必須依據實證為基礎的實務工作，使用研究來評估效果和介入 的適當性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07457', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「對食物或醫療等照顧服務的提供有所保留，以致無法滿足老人的基本需求」，上述屬於何種類型的老 人虐待（elder abuse）？', '["經濟剝削", "身體虐待", "心理虐待", "疏忽"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07458', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「從全面性的觀點去關心案主，不侷限在學生、學校、社區、家庭等單獨系統的協助，而是關注在案主 與其周遭各種影響因素的交互作用，以有效協助有困擾的學生」，這屬於何種學校社會工作模式？', '["傳統臨床模式（traditional-clinical model）", "社會互動模式（social interaction model）", "學校變遷模式（school-change model）", "社區學校模式（community school model）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07459', 'social-worker', 'social-worker-moex-100-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「當一位坐輪椅的身心障礙女性去應徵工作時，發現應徵場所沒有任何的無障礙環境，包括：輪椅坡道、 能讓輪椅進入的電梯與門等，於是她感到不受尊重而離開，並放棄了應徵工作的機會」。針對上述情境， 當社會工作者運用與雇主協商的方式，請單位能改變應徵的地點與設備，讓該婦女能夠順利應徵；並在 婦女順利工作之後，協助雇主申請職務再設計的經費，以改善不適於身心障礙者工作的坡道、電梯與辦 公室入口門等，此時社會工作者是以何種模式的思維來提供服務？', '["社會模式（social model）", "個人模式（individual model）", "醫療模式（medical model）", "傳統模式（traditional model）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "eceb38fb39b6", "answer_pdf_sha1": "5071a2652ded", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
